where exists (select 1 from employees e where lower(e.email) = lower(v.email))
  and exists (select 1 from rooms r where r.name = v.room)
  and v.end_at::timestamptz > v.start_at::timestamptz;

select count(*) as imported from room_bookings where status='cancelled';
